{
  "name": "BioCloud Pro",
  "description": "An enterprise-grade bioinformatics SaaS platform for high-throughput NGS data analysis, featuring automated pipelines, interactive visualizations, and AI-driven biological insights."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PipelineStatus {
  PENDING = 'Pending',
  RUNNING = 'Running',
  COMPLETED = 'Completed',
  FAILED = 'Failed'
}

export type Species = 'Homo sapiens' | 'Mus musculus' | 'Rattus norvegicus' | 'Drosophila melanogaster';

export interface Project {
  id: string;
  name: string;
  description: string;
  createdAt: string;
  status: PipelineStatus;
  progress: number;
}

export interface Sample {
  id: string;
  name: string;
  size: string;
  type: 'FASTQ' | 'BAM' | 'VCF';
  uploadDate: string;
}

export interface AnalysisResult {
  id: string;
  type: 'RNA-Seq' | 'WES' | 'SingleCell';
  summary: string;
  charts: {
    volcano?: any[];
    enrichment?: any[];
    heatmap?: any[];
  };
}

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { PipelineWizard } from './components/PipelineWizard';
import { ResultsDashboard } from './components/ResultsDashboard';
import { AIAssistant } from './components/AIAssistant';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'dashboard' | 'wizard' | 'results'>('dashboard');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);

  const navigateTo = (view: 'dashboard' | 'wizard' | 'results', projectId?: string) => {
    setCurrentView(view);
    if (projectId) setSelectedProjectId(projectId);
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard onNewProject={() => navigateTo('wizard')} onViewResults={(id) => navigateTo('results', id)} />;
      case 'wizard':
        return <PipelineWizard onCancel={() => navigateTo('dashboard')} onStart={() => navigateTo('dashboard')} />;
      case 'results':
        return <ResultsDashboard projectId={selectedProjectId!} onBack={() => navigateTo('dashboard')} />;
      default:
        return <Dashboard onNewProject={() => navigateTo('wizard')} onViewResults={(id) => navigateTo('results', id)} />;
    }
  };

  return (
    <Layout activeView={currentView} onNavigate={navigateTo}>
      <div className="flex flex-col lg:flex-row gap-6 p-4 md:p-8 min-h-screen">
        <main className="flex-1 overflow-y-auto">
          {renderContent()}
        </main>

        {/* Floating AI Assistant - Present on all views for guidance */}
        <aside className="w-full lg:w-96 flex-shrink-0">
          <AIAssistant />
        </aside>
      </div>
    </Layout>
  );
};

export default App;

import React from 'react';
