              <p className="text-sm font-semibold text-slate-900">Dr. Sarah Chen</p>
              <p className="text-xs text-slate-500">Principal Investigator</p>
            </div>
            <div className="w-10 h-10 rounded-full bg-blue-100 border-2 border-white flex items-center justify-center text-blue-600 font-bold shadow-sm">
              SC
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto">
          {children}
        </main>
      </div>
    </div>
  );
};

