const StatusBadge: React.FC<{ status: PipelineStatus }> = ({ status }) => {
  const configs = {
    [PipelineStatus.COMPLETED]: { color: 'bg-emerald-50 text-emerald-700 border-emerald-100', icon: CheckCircle2 },
    [PipelineStatus.RUNNING]: { color: 'bg-blue-50 text-blue-700 border-blue-100', icon: Clock },
    [PipelineStatus.PENDING]: { color: 'bg-slate-50 text-slate-700 border-slate-100', icon: AlertCircle },
    [PipelineStatus.FAILED]: { color: 'bg-rose-50 text-rose-700 border-rose-100', icon: AlertCircle },
  };

  const config = configs[status];

  return (
    <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full border text-xs font-bold ${config.color}`}>
      <config.icon className="w-3.5 h-3.5" />
      {status}
    </span>
  );
};

import React, { useState } from 'react';
import { ChevronRight, ChevronLeft, Upload, Dna, Settings2, Play, Info } from 'lucide-react';
import { Species } from '../types';

interface WizardProps {
  onCancel: () => void;
  onStart: () => void;
}

export const PipelineWizard: React.FC<WizardProps> = ({ onCancel, onStart }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    type: 'RNA-seq',
    species: 'Homo sapiens' as Species,
    refGenome: 'GRCh38',
    samples: [] as File[],
  });

  const nextStep = () => setStep(s => Math.min(s + 1, 4));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const renderStepContent = () => {
    switch(step) {
      case 1:
        return (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Project Identity</label>
              <input 
                type="text" 
                placeholder="e.g. Breast Cancer Cell Line RNA-seq"
                className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Analysis Pipeline</label>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {['RNA-seq', 'Whole Exome (WES)', 'Single-Cell (scRNA)', 'ChIP-seq'].map(type => (
                  <button
                    key={type}
                    onClick={() => setFormData({...formData, type})}
                    className={`p-4 rounded-xl border-2 text-left transition-all ${
                      formData.type === type ? 'border-blue-600 bg-blue-50 ring-2 ring-blue-100' : 'border-slate-100 bg-white hover:border-slate-200'
                    }`}
                  >
                    <p className="font-bold text-slate-900">{type}</p>
                    <p className="text-xs text-slate-500 mt-1">Standardized research pipeline</p>
                  </button>
                ))}
              </div>
            </div>
          </div>
        );
      case 2:
        return (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
            <div className="border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center bg-slate-50/50">
              <div className="bg-white w-16 h-16 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-center mx-auto mb-4">
                <Upload className="w-8 h-8 text-blue-600" />
              </div>
              <h3 className="text-lg font-bold text-slate-900">Upload FASTQ Data</h3>
              <p className="text-slate-500 mt-2 max-w-sm mx-auto text-sm">
                Drag and drop your raw sequencing files here. Supports .fastq, .fq.gz, .bam.
              </p>
              <input type="file" multiple className="hidden" id="file-upload" />
              <label htmlFor="file-upload" className="mt-6 inline-block bg-white border border-slate-200 px-6 py-2.5 rounded-xl font-semibold text-slate-700 hover:bg-slate-50 cursor-pointer shadow-sm">
                Select Files
              </label>
              <div className="mt-4 flex items-center justify-center gap-2 text-xs text-slate-400">
                <Info className="w-4 h-4" />
                Supports multi-part resumable uploads up to 500GB
              </div>
            </div>
          </div>
        );
      case 3:
        return (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Species Selection</label>
                  <select 
                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                    value={formData.species}
                    onChange={e => setFormData({...formData, species: e.target.value as Species})}
                  >
                    <option>Homo sapiens</option>
                    <option>Mus musculus</option>
                    <option>Rattus norvegicus</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Reference Genome</label>
                  <select 
                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                    value={formData.refGenome}
                    onChange={e => setFormData({...formData, refGenome: e.target.value})}
                  >
                    <option>GRCh38 (latest)</option>
                    <option>h19 / GRCh37</option>
                    <option>T2T-CHM13</option>
                  </select>
                </div>
             </div>
             <div className="bg-amber-50 border border-amber-100 p-4 rounded-xl flex gap-3">
               <Settings2 className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
               <p className="text-sm text-amber-800">
                 <strong>Advanced Tip:</strong> We've pre-configured the alignment (STAR) and quantification (RSEM) parameters based on your species selection. These are recommended for academic publication.
               </p>
             </div>
          </div>
        );
      case 4:
        return (
          <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
            <div className="bg-slate-900 rounded-2xl p-8 text-white relative overflow-hidden">
              <div className="relative z-10">
                <h3 className="text-2xl font-bold mb-2">Ready to Launch</h3>
                <p className="text-slate-400">Review your configurations before initiating the cloud compute cluster.</p>

                <div className="grid grid-cols-2 gap-8 mt-8">
                  <div>
                    <p className="text-xs text-slate-500 uppercase tracking-widest font-bold">Pipeline</p>
                    <p className="text-lg font-semibold">{formData.type}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-500 uppercase tracking-widest font-bold">Species</p>
                    <p className="text-lg font-semibold">{formData.species}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-500 uppercase tracking-widest font-bold">Resources</p>
                    <p className="text-lg font-semibold">16 CPU / 64GB RAM</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-500 uppercase tracking-widest font-bold">Est. Duration</p>
                    <p className="text-lg font-semibold">4.5 Hours</p>
                  </div>
                </div>
              </div>
              <Dna className="absolute -right-12 -bottom-12 w-64 h-64 text-slate-800 opacity-20" />
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-8 space-y-8">
      {/* Wizard Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Launch Analysis</h1>
          <p className="text-slate-500">Configure your automated bioinformatics workflow.</p>
        </div>
        <button onClick={onCancel} className="text-slate-400 hover:text-slate-600 font-medium">Cancel</button>
      </div>

      {/* Progress Bar */}
      <div className="flex gap-4">
        {[1, 2, 3, 4].map(i => (
          <div key={i} className={`flex-1 h-2 rounded-full transition-all duration-500 ${step >= i ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
        ))}
      </div>

      {/* Main Content Card */}
      <div className="bg-white border border-slate-200 rounded-3xl shadow-xl shadow-slate-200/50 p-8 min-h-[450px] flex flex-col">
        <div className="flex-1">
          <div className="flex items-center gap-3 mb-8">
            <div className="w-10 h-10 rounded-xl bg-blue-100 flex items-center justify-center text-blue-600 font-bold">
              {step}
            </div>
            <h2 className="text-xl font-bold text-slate-900">
              {step === 1 && "Project Details"}
              {step === 2 && "Data Management"}
              {step === 3 && "Parameters Config"}
              {step === 4 && "Final Review"}
            </h2>
          </div>

          {renderStepContent()}
        </div>

        <div className="flex items-center justify-between mt-12 pt-8 border-t border-slate-100">
          <button 
            onClick={prevStep}
            disabled={step === 1}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-semibold transition-all ${
              step === 1 ? 'text-slate-300 cursor-not-allowed' : 'text-slate-600 hover:bg-slate-100'
            }`}
          >
            <ChevronLeft className="w-5 h-5" />
            Previous
          </button>

          {step < 4 ? (
            <button 
              onClick={nextStep}
              className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-xl font-semibold flex items-center gap-2 transition-all shadow-lg shadow-blue-200"
            >
              Next Step
              <ChevronRight className="w-5 h-5" />
            </button>
          ) : (
            <button 
              onClick={onStart}
              className="bg-emerald-600 hover:bg-emerald-700 text-white px-8 py-2.5 rounded-xl font-semibold flex items-center gap-2 transition-all shadow-lg shadow-emerald-200 animate-pulse"
            >
              <Play className="w-5 h-5 fill-current" />
              Launch Pipeline
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, Send, BrainCircuit, X, MessageSquare, ListFilter } from 'lucide-react';
import { GoogleGenAI } from '@google/genai';

export const AIAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(true);
  const [messages, setMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: "Hello! I'm your BioCloud AI assistant. I can help interpret your analysis results, suggest pathways to explore, or assist with pipeline configuration. What's on your mind today?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMsg,
        config: {
          systemInstruction: `You are a world-class bioinformatics assistant. Help the user with:
          1. Interpreting gene lists (GO/KEGG).
          2. Explaining NGS pipeline steps (Alignment, QC, Quantification).
          3. Writing academic descriptions for results sections.
          4. Recommending downstream analysis based on results.
          Keep answers professional, evidence-based, and concise. Use markdown for tables or lists.`
        }
      });

      const aiText = response.text || "I'm sorry, I couldn't process that request.";
      setMessages(prev => [...prev, { role: 'ai', text: aiText }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', text: "Connection error. Please ensure your environment is configured correctly." }]);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-8 right-8 bg-blue-600 text-white p-4 rounded-full shadow-2xl hover:bg-blue-700 transition-all z-50 flex items-center gap-2 group"
      >
        <Sparkles className="w-6 h-6 animate-pulse" />
        <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 font-bold">Ask AI</span>
      </button>
    );
  }

  return (
    <div className="bg-white rounded-3xl border border-slate-200 shadow-2xl flex flex-col h-[calc(100vh-120px)] sticky top-8 animate-in slide-in-from-right-4">
      {/* Header */}
      <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-blue-50/50 rounded-t-3xl">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-xl text-white">
            <BrainCircuit className="w-5 h-5" />
          </div>
          <div>
            <h3 className="font-bold text-slate-900 text-sm">BioCloud AI</h3>
            <div className="flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
              <span className="text-[10px] text-slate-500 font-medium">Gemini 3 Flash Connected</span>
            </div>
          </div>
        </div>
        <button onClick={() => setIsOpen(false)} className="p-2 text-slate-400 hover:text-slate-600">
          <X className="w-4 h-4" />
        </button>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-3 text-sm shadow-sm ${
              m.role === 'user' ? 'bg-blue-600 text-white' : 'bg-white border border-slate-100 text-slate-800'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 rounded-2xl p-3 shadow-sm flex gap-2">
              <span className="w-2 h-2 rounded-full bg-blue-400 animate-bounce"></span>
              <span className="w-2 h-2 rounded-full bg-blue-400 animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-2 h-2 rounded-full bg-blue-400 animate-bounce [animation-delay:0.4s]"></span>
            </div>
          </div>
        )}
      </div>

      {/* Quick Suggestions */}
      <div className="p-3 bg-white border-t border-slate-100 flex gap-2 overflow-x-auto">
        {['Summarize results', 'Identify outliers', 'Pathway help'].map(s => (
          <button 
            key={s} 
            onClick={() => { setInput(s); }}
            className="whitespace-nowrap px-3 py-1.5 rounded-full border border-slate-200 text-xs font-medium text-slate-600 hover:bg-slate-50 transition-colors"
          >
            {s}
          </button>
        ))}
      </div>

      {/* Input */}
      <div className="p-4 bg-white rounded-b-3xl">
        <div className="relative">
          <textarea 
            rows={1}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSend())}
            placeholder="Ask about your biological data..."
            className="w-full pl-4 pr-12 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-sm resize-none"
          />
          <button 
            onClick={handleSend}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 disabled:opacity-50"
            disabled={!input.trim() || isLoading}
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async getReportSummary(projectName: string, geneList: string[]) {
    const prompt = `Analyze this list of top differentially expressed genes from the project "${projectName}": ${geneList.join(', ')}. 
    Summarize the biological significance and suggest 2-3 pathways for downstream validation.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Unable to generate summary at this time.";
    }
  }

  async suggestPipeline(sampleType: string, species: string) {
    const prompt = `Suggest an optimal bioinformatics pipeline for ${sampleType} data from ${species}. List key software tools (aligner, quantifier, QC) and why.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text;
    } catch (error) {
      return "Unable to provide pipeline suggestions.";
    }
  }
}

